INSERT INTO problems (theme_id, title, level, type, statement, requirements, hint, answer, explanation, common_mistakes, display_order) VALUES ('11111111-1111-1111-1111-111111111111', 'Taskクラスの作成', 1, 'normal', 'TODOアプリで扱うTaskクラスを作成してください。', 'id (int), title (String), isCompleted (boolean) のフィールドを持つこと。全フィールドを初期化するコンストラクタを持つこと。', 'アクセス修飾子は private にし、getter/setterは省略してよいです。', E'public class Task {\n    private int id;\n    private String title;\n    private boolean isCompleted;\n\n    public Task(int id, String title, boolean isCompleted) {\n        this.id = id;\n        this.title = title;\n        this.isCompleted = isCompleted;\n    }\n}', 'クラスの基本的な構成を理解するための問題です。', 'thisをつけ忘れるミス', 1);
INSERT INTO problems (theme_id, title, level, type, statement, requirements, hint, answer, explanation, common_mistakes, display_order) VALUES ('11111111-1111-1111-1111-111111111111', 'タスクの追加メソッド', 1, 'normal', 'TaskManagerクラスにタスクを追加するaddTaskメソッドを作成してください。', 'List<Task> をフィールドに持つこと。addTask(Task task) メソッドでリストにタスクを追加すること。', 'ArrayListを使いましょう。', E'public class TaskManager {\n    private List<Task> tasks = new ArrayList<>();\n\n    public void addTask(Task task) {\n        tasks.add(task);\n    }\n}', 'Listの初期化とメソッドによる操作の基本を学びます。', 'Listの初期化を忘れてNullPointerExceptionになるミス', 2);
INSERT INTO problems (theme_id, title, level, type, statement, requirements, hint, answer, explanation, common_mistakes, display_order) VALUES ('11111111-1111-1111-1111-111111111111', 'タスクの完了処理', 2, 'normal', '指定されたIDのタスクを完了状態にするcompleteTaskメソッドを作成してください。', 'completeTask(int id) メソッドを作成すること。該当するIDのタスクのisCompletedをtrueにすること。', 'for文でリストを走査し、idが一致するものを見つけましょう。', E'public void completeTask(int id) {\n    for (Task task : tasks) {\n        if (task.getId() == id) {\n            task.setCompleted(true);\n            break;\n        }\n    }\n}', 'リストの走査と条件分岐を組み合わせた処理です。', '==とequalsの混同', 3);
INSERT INTO problems (theme_id, title, level, type, statement, requirements, hint, answer, explanation, common_mistakes, display_order) VALUES ('22222222-2222-2222-2222-222222222222', 'メールアドレスのバリデーション', 1, 'normal', 'メールアドレスが正しい形式かどうかを判定するisValidEmailメソッドを作成してください。', 'nullまたは空文字の場合はfalseを返すこと。@が含まれていない場合はfalseを返すこと。', 'String#contains()メソッドが使えます。', E'public boolean isValidEmail(String email) {\n    if (email == null || email.isEmpty()) {\n        return false;\n    }\n    return email.contains("@");\n}', 'nullチェックを最初に行うことでNullPointerExceptionを防ぎます。', 'nullチェックを忘れるミス', 1);
INSERT INTO problems (theme_id, title, level, type, statement, requirements, hint, answer, explanation, common_mistakes, display_order) VALUES ('33333333-3333-3333-3333-333333333333', '完了済みタスクの抽出', 1, 'fill_blank', E'List<Task> から、isCompleted が true のものだけを抽出してください。\n\nList<Task> completed = tasks.stream()\n    .filter(task -> __________)\n    .collect(Collectors.toList());', 'Stream APIのfilterを使用すること', 'filterの中にはboolean値を返すラムダ式を書きます。', 'task.isCompleted()', 'filter内では関数型インターフェースに基づくラムダ式を使います。', '冗長な書き方をしてしまう', 1);
